-- 2084_rewrite_exercise_instructions.sql
-- Auto-generated by backend/scripts/rewrite_exercise_instructions.py.
-- Rewrites deficient exercise instructions using the app's own vetted
-- instruction engine, routed by a correct deterministic classifier.
-- Backs up originals first. NO LLM. The MV refresh is NOT here —
-- apply_2084_rewrite.py runs it separately (REFRESH ... CONCURRENTLY
-- cannot run inside a transaction).

CREATE TABLE IF NOT EXISTS public.exercise_instruction_backup (
    id uuid NOT NULL,
    source_table text NOT NULL,
    old_instructions text,
    new_instructions text,
    movement_class text,
    rewrite_method text NOT NULL DEFAULT 'rule',
    source_citation text,
    rewrite_batch text NOT NULL,
    backed_up_at timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (id, rewrite_batch)
);

INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Stand with feet shoulder-width apart.
2. Grip the weight with palms facing up.
3. Keep your elbows close to your sides.
4. Curl the weight toward your shoulders.
5. Lower with control to full arm extension.
6. Breathing: Inhale at the bottom with arms fully extended. Exhale as you curl the weight up. Inhale on the slow eccentric back down.
7. Form check: Upper arms stay stationary — do not let elbows drift forward.
8. Form check: No swinging the weight or rocking the torso.
9. The Alternate Biceps Curl Standing Dumbbells mainly trains your Biceps (Biceps Brachii). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'curl',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=curl] NASM EPFT 6th ed. ch.13 — single-joint resistance technique$instr$, '2084-2026-05-18'
