  AND NOT EXISTS (SELECT 1 FROM public.exercise_instruction_backup
                  WHERE id = '7836c152-2c22-41db-912c-994b2a6f7d96');
UPDATE public.exercise_library SET instructions = $instr$1. Position the bar on your upper back (not your neck).
2. Stand with feet shoulder-width apart, toes slightly pointed out.
3. Brace your core before descending.
4. Keep your knees tracking over your toes.
5. Descend until thighs are at least parallel to the floor.
6. Breathing: Take a big belly-breath before you descend and brace your core. Hold the brace through the bottom of the rep. Exhale forcefully on the drive up.
7. Form check: Weight in your heels and mid-foot.
8. Form check: Go as deep as your mobility allows with good form.
9. The Barbell Full Squat(Back) mainly trains your Quadriceps (Quadriceps Femoris), Glutes (gluteus maximus, gluteus mideus). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$ WHERE id = '7836c152-2c22-41db-912c-994b2a6f7d96';

INSERT INTO public.exercise_instruction_backup
