INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Set up in a plank — hands slightly wider than shoulders, fingers spread.
2. Squeeze glutes and brace the core so hips stay level (no sag, no pike).
3. Lower the chest to the floor with elbows tucked at ~45°.
4. Drive the floor away to push back up — long arms at the top.
5. Reset, breathe, and repeat.
6. Breathing: Inhale on the descent — keep the core braced. Exhale forcefully as you press back up. Reset the breath between reps if your tempo allows.
7. Form check: Squeeze the glutes — keep the body in one straight line.
8. Form check: Elbows tucked at ~45°, not flared out at 90°.
9. The Clock Push Ups mainly trains your Chest (Pectoralis Major), Triceps (Triceps Brachii). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'pushup',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=pushup] NSCA ESSC 4th ed. ch.13; NASM EPFT 6th ed. ch.13 — horizontal pressing$instr$, '2084-2026-05-18'
FROM public.exercise_library WHERE id = 'df96c033-2fca-4ea7-9b53-1f2032b37193'
  AND NOT EXISTS (SELECT 1 FROM public.exercise_instruction_backup
                  WHERE id = 'df96c033-2fca-4ea7-9b53-1f2032b37193');
