INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Stand tall with feet hip-width apart, core braced.
2. Step forward (or back) into a long lunge stance.
3. Lower until both knees form ~90° angles — rear knee just off the floor.
4. Keep your front knee tracking over your toes, not collapsing inward.
5. Drive through the front heel to return to standing.
6. Breathing: Inhale as you step out and descend. Exhale as you drive through the front heel and stand.
7. Form check: Front knee tracks over the toes — never caves inward.
8. Form check: Step long enough that the rear knee can comfortably reach the floor.
9. The Curtsy Lunges Resistance Band mainly trains your Glutes (gluteus maximus, gluteus mideus). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'lunge',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=lunge] NSCA ESSC 4th ed. ch.13 — lunge / split-stance technique$instr$, '2084-2026-05-18'
FROM public.exercise_library WHERE id = '349f24d8-c645-4120-ba0a-14adac67bc0f'
  AND NOT EXISTS (SELECT 1 FROM public.exercise_instruction_backup
                  WHERE id = '349f24d8-c645-4120-ba0a-14adac67bc0f');
UPDATE public.exercise_library SET instructions = $instr$1. Stand tall with feet hip-width apart, core braced.
