INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Set the cable / band roughly at face height (rope or straight band).
2. Step back to create tension, arms long.
3. Pull the rope/band toward your face — elbows up and out.
4. Externally rotate at the top: knuckles point back behind the ears.
5. Return slowly under control.
6. Breathing: Inhale as you set up with arms extended. Exhale through the pull — squeeze the rear delts. Inhale on the controlled return.
7. Form check: Lead with the elbows — they move up and out.
8. Form check: Externally rotate at the top — knuckles point back.
9. The Dumbbell Bent-Over Face Pull mainly trains your Shoulders (Posterior Deltoids), Upper Back (Trapezius, Rhomboids). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'face_pull',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=face_pull] NSCA ESSC 4th ed. ch.13 — rowing / pulling technique$instr$, '2084-2026-05-18'
FROM public.exercise_library WHERE id = 'b2e47ce1-235e-427d-a39b-64fb0d85c0a9'
  AND NOT EXISTS (SELECT 1 FROM public.exercise_instruction_backup
                  WHERE id = 'b2e47ce1-235e-427d-a39b-64fb0d85c0a9');
UPDATE public.exercise_library SET instructions = $instr$1. Set the cable / band roughly at face height (rope or straight band).
2. Step back to create tension, arms long.
3. Pull the rope/band toward your face — elbows up and out.
4. Externally rotate at the top: knuckles point back behind the ears.
5. Return slowly under control.
6. Breathing: Inhale as you set up with arms extended. Exhale through the pull — squeeze the rear delts. Inhale on the controlled return.
7. Form check: Lead with the elbows — they move up and out.
8. Form check: Externally rotate at the top — knuckles point back.
9. The Dumbbell Bent-Over Face Pull mainly trains your Shoulders (Posterior Deltoids), Upper Back (Trapezius, Rhomboids). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$ WHERE id = 'b2e47ce1-235e-427d-a39b-64fb0d85c0a9';

INSERT INTO public.exercise_instruction_backup
