INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Hinge at the hips with a slight knee bend.
2. Keep your back flat and core engaged.
3. Grip the weight with arms extended.
4. Pull the weight toward your lower chest/upper abs.
5. Squeeze your shoulder blades together at the top.
6. Breathing: Inhale at the stretched position with arms extended. Exhale as you pull the weight in and squeeze the back. Inhale again on the controlled return.
7. Form check: Initiate the pull with the back, not the arms.
8. Form check: Core tight — do not let the lower back arch.
9. The Lawnmower Row mainly trains your Back (Latissimus Dorsi, Rhomboids). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'barbell_row',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=barbell_row] NSCA ESSC 4th ed. ch.13 — rowing / pulling technique$instr$, '2084-2026-05-18'
FROM public.exercise_library WHERE id = '8c6fb3c2-5877-4a91-9882-bdf6e11256bf'
  AND NOT EXISTS (SELECT 1 FROM public.exercise_instruction_backup
                  WHERE id = '8c6fb3c2-5877-4a91-9882-bdf6e11256bf');
UPDATE public.exercise_library SET instructions = $instr$1. Hinge at the hips with a slight knee bend.
2. Keep your back flat and core engaged.
3. Grip the weight with arms extended.
4. Pull the weight toward your lower chest/upper abs.
5. Squeeze your shoulder blades together at the top.
6. Breathing: Inhale at the stretched position with arms extended. Exhale as you pull the weight in and squeeze the back. Inhale again on the controlled return.
7. Form check: Initiate the pull with the back, not the arms.
8. Form check: Core tight — do not let the lower back arch.
9. The Lawnmower Row mainly trains your Back (Latissimus Dorsi, Rhomboids). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$ WHERE id = '8c6fb3c2-5877-4a91-9882-bdf6e11256bf';

INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Set up on forearms (or palms) with elbows under the shoulders.
2. Squeeze the glutes and tuck the pelvis — straight line head to heels.
3. Press the floor away to lift the upper back slightly.
4. Brace the core like you are bracing for a punch.
5. Hold for the prescribed time without sagging or piking.
6. Breathing: Breathe steadily — short, shallow breaths are fine. Do not hold your breath; that spikes blood pressure and shortens the hold. Exhale a touch more forcefully on each breath to keep the core braced.
7. Form check: Squeeze glutes; tuck the pelvis — no sag, no pike.
8. Form check: Press the floor away — pack the shoulders.
9. The Long Lever Plank mainly trains your Core (Rectus Abdominis, Transverse Abdominis). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'plank',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=plank] NASM EPFT 6th ed. ch.9; McGill, Low Back Disorders 2nd ed. — trunk / core training$instr$, '2084-2026-05-18'
FROM public.exercise_library WHERE id = '43ff0bdc-fe3c-445b-b5ca-9e24229665ca'
  AND NOT EXISTS (SELECT 1 FROM public.exercise_instruction_backup
                  WHERE id = '43ff0bdc-fe3c-445b-b5ca-9e24229665ca');
UPDATE public.exercise_library SET instructions = $instr$1. Set up on forearms (or palms) with elbows under the shoulders.
2. Squeeze the glutes and tuck the pelvis — straight line head to heels.
